import math
import xml.etree.ElementTree as et
from typing import (
    Union,
    Tuple,
    Iterator,
    Optional,
    Iterable,
    Any,
    Dict,
    List,
    Sequence,
    Callable,
)

from typing_extensions import Self

Number = Union[float, int]


class OrientationError(Exception):
    """Raised when something bad happens with orientations within bounding boxes"""


def findtext(element: et.Element, path: str) -> str:
    text: Optional[str] = element.findtext(path)
    if text is None:
        raise AttributeError(f"'{path}' not found in element '{element.tag}'")
    return text


class BoundingBox:
    """Represent a 2D BoundingBox in an image frame, where the origin is at the top-left corner. The x axis is
    left-ascending and the y axis down-ascending.
    """

    def __init__(self, xmin: Number, ymin: Number, xmax: Number, ymax: Number) -> None:
        if xmin > xmax:
            raise ValueError(f"xmin ({xmin}) cannot be superior to xmax ({xmax})")

        if ymin > ymax:
            raise ValueError(f"ymin ({ymin}) cannot be superior to ymax ({ymax})")

        self.xmin = xmin
        self.ymin = ymin
        self.xmax = xmax
        self.ymax = ymax

    @property
    def width(self) -> Number:
        return self.xmax - self.xmin

    @property
    def height(self) -> Number:
        return self.ymax - self.ymin

    @property
    def shape(self) -> Tuple[Number, Number]:
        return self.width, self.height

    @property
    def point_min(self) -> Tuple[Number, Number]:
        return self.xmin, self.ymin

    @property
    def point_max(self) -> Tuple[Number, Number]:
        return self.xmax, self.ymax

    @property
    def points(
        self,
    ) -> Tuple[
        Tuple[Number, Number],
        Tuple[Number, Number],
        Tuple[Number, Number],
        Tuple[Number, Number],
    ]:
        return (
            (self.xmin, self.ymin),
            (self.xmax, self.ymin),
            (self.xmin, self.ymax),
            (self.xmax, self.ymax),
        )

    @property
    def area(self) -> Number:
        return self.width * self.height

    @property
    def center(self) -> Tuple[Number, Number]:
        return (self.xmax + self.xmin) / 2, (self.ymax + self.ymin) / 2

    @property
    def is_null(self) -> bool:
        return math.isclose(self.width, 0.0) or math.isclose(self.height, 0.0)

    @property
    def longest_edge(self) -> Number:
        """Return axis which have the longest edge, returns width (axis 0) if both edges share the same length"""
        return 0 if self.width >= self.height else 1

    def set_shape(self, shape: Tuple[Number, Number]) -> None:
        """Changes xmin, ymin, xmax, ymax according to current center and new shape"""
        dx = shape[0] / 2.0
        dy = shape[1] / 2.0
        center = self.center
        self.xmin = center[0] - dx
        self.ymin = center[1] - dy
        self.xmax = center[0] + dx
        self.ymax = center[1] + dy

    def set_center(self, center: Tuple[Number, Number]) -> None:
        """Changes xmin, ymin, xmax, ymax according to current center and new shape"""
        dx = self.shape[0] / 2.0
        dy = self.shape[1] / 2.0
        self.xmin = center[0] - dx
        self.ymin = center[1] - dy
        self.xmax = center[0] + dx
        self.ymax = center[1] + dy

    def grow(self, coords: Iterable[Number]) -> None:
        coords = tuple(coords)
        try:
            xmin, ymin, xmax, ymax = coords
        except ValueError:
            xmin, ymin = xmax, ymax = coords

        self.xmin = min(self.xmin, xmin)
        self.ymin = min(self.ymin, ymin)

        self.xmax = max(self.xmax, xmax)
        self.ymax = max(self.ymax, ymax)

    def apply_padding(self, value: Number) -> None:
        """if npix > 0 then bounding box will extend, if < 0 bounding box will shrink"""
        new_shape = (self.shape[0] + value * 2, self.shape[1] + value * 2)
        self.set_shape(new_shape)

    def subtract(self, x: Number, y: Number) -> Self:
        """Translates the bounding box by subtracting its coordinates by (x, y)"""
        self.xmin -= x
        self.ymin -= y
        self.xmax -= x
        self.ymax -= y
        return self

    def astype(self, newtype: Callable[[Number], Number]) -> Self:
        """Returns a new BoundingBox with coordinates casted as the 'newtype'

        :param newtype: the new type the BoundingBox Coordinates should be (e.g: int, float)
        """
        return self.__class__(
            newtype(self.xmin),
            newtype(self.ymin),
            newtype(self.xmax),
            newtype(self.ymax),
        )

    def coords_are_integer(self) -> bool:
        return all(v % 1 == 0 for v in self)

    def intersection(self, other: Self) -> Optional[Self]:
        """Compute the intersection between self and other

        :param other: The other BoundingBox
        :return: None if the boxes do not overlap, or new BoundingBox representing the overlap between self and other.
        """
        top_left_point = max(self.xmin, other.xmin), max(self.ymin, other.ymin)
        bottom_right_point = min(self.xmax, other.xmax), min(self.ymax, other.ymax)

        bbox = None
        try:
            bbox = self.from_points(top_left_point, bottom_right_point)
            if bbox.is_null:
                bbox = None
        except ValueError:
            pass
        return bbox

    def intersect_over_union(self, other: Self) -> float:
        """Returns the computed 'Intersect over Union' between self and other box."""
        intersection: Optional[Self] = self.intersection(other)
        if intersection is None:
            return 0.0
        return intersection.area / (self.area + other.area - intersection.area)

    def contains_coord(self, other: Tuple[Number, Number]) -> bool:
        return (self.xmin <= other[0] <= self.xmax) & (
            self.ymin <= other[1] <= self.ymax
        )

    def __contains__(self, item: Self) -> bool:
        """Returns true if the bounding box pointed by 'item' is fully contained inside self."""
        all_corner_coords = item.to_quad()
        return all(
            (self.xmin <= x <= self.xmax) and (self.ymin <= y <= self.ymax)
            for x, y in all_corner_coords
        )

    def __iter__(self) -> Iterator[Number]:
        """Returns an iterator over coordinates"""
        return (getattr(self, p) for p in ["xmin", "ymin", "xmax", "ymax"])

    def __hash__(self) -> int:
        return hash((self.xmin, self.ymin, self.xmax, self.ymax))

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, BoundingBox):
            raise NotImplementedError
        return all(
            [
                self.xmin == other.xmin,
                self.ymin == other.ymin,
                self.xmax == other.xmax,
                self.ymax == other.ymax,
            ]
        )

    def __repr__(self) -> str:
        return f"<BoundingBox(xmin: {self.xmin}, ymin: {self.ymin}, xmax: {self.xmax}, ymax: {self.ymax})>"

    @classmethod
    def from_points(
        cls, point_min: Tuple[Number, Number], point_max: Tuple[Number, Number]
    ) -> Self:
        return cls(point_min[0], point_min[1], point_max[0], point_max[1])

    @classmethod
    def from_shape(
        cls, point_min: Tuple[Number, Number], width: Number, height: Number
    ) -> Self:
        xmin, ymin = point_min
        point_max = xmin + width, ymin + height
        return cls.from_points(point_min, point_max)

    def write_node(self, root: et.Element) -> et.Element:
        """Write a XML subelement and returns it for further information addition by child classes"""
        bndbox: et.Element = et.SubElement(root, "bndbox")
        et.SubElement(bndbox, "xmin").text = str(self.xmin)
        et.SubElement(bndbox, "ymin").text = str(self.ymin)
        et.SubElement(bndbox, "xmax").text = str(self.xmax)
        et.SubElement(bndbox, "ymax").text = str(self.ymax)
        return bndbox

    @classmethod
    def from_xml_node(cls, root: et.Element) -> Self:
        return cls(
            int(findtext(root, "xmin")),
            int(findtext(root, "ymin")),
            int(findtext(root, "xmax")),
            int(findtext(root, "ymax")),
        )

    @classmethod
    def from_dict(cls, infos: Dict[str, Any]) -> Self:
        """Instantiate a bounding box from a dictionary having proper keys.
        (Usually keys are the attribute name in Uppercase)"""
        return cls(infos["xmin"], infos["ymin"], infos["xmax"], infos["ymax"])

    def to_dict(self) -> Dict[str, Any]:
        center = self.center
        shape = self.shape
        return {
            "xmin": self.xmin,
            "ymin": self.ymin,
            "xmax": self.xmax,
            "ymax": self.ymax,
            "center_x": center[0],
            "center_y": center[1],
            "width": shape[0],
            "height": shape[1],
        }

    @classmethod
    def from_quad(cls, quad: List[Tuple[Number, Number]]) -> Self:
        """Quad is a list of XY coordinates"""
        xs, ys = zip(*(point for point in quad))
        return cls(min(xs), min(ys), max(xs), max(ys))

    def to_quad(self) -> List[Tuple[Number, Number]]:
        """Returns a list of XY coordinates"""
        return [
            (self.xmin, self.ymin),
            (self.xmin, self.ymax),
            (self.xmax, self.ymax),
            (self.xmax, self.ymin),
        ]


class DetectionBox(BoundingBox):
    """BoundingBox with additional information resulting from a detection or classification"""

    def __init__(
        self,
        xmin: Number,
        ymin: Number,
        xmax: Number,
        ymax: Number,
        score: float,
        class_id: int = 0,
        class_name: str = "N/A",
    ):
        super().__init__(xmin, ymin, xmax, ymax)
        self.score = score
        self.class_id = class_id
        self.class_name = class_name

    @property
    def score_pct(self) -> float:
        return self.score * 100

    def __repr__(self) -> str:
        return f"{super().__repr__()} score: {self.score}, class_id: {self.class_id}"

    @classmethod
    def from_bounding_box(
        cls,
        box: BoundingBox,
        score: float = 0.0,
        class_id: int = 0,
        class_name: str = "N/A",
    ) -> Self:
        return cls(
            box.xmin,
            box.ymin,
            box.xmax,
            box.ymax,
            score=score,
            class_id=class_id,
            class_name=class_name,
        )

    @classmethod
    def from_tf_detection(
        cls,
        box: Sequence[Number],
        score: float,
        class_id: int,
        img_size: Tuple[Number, Number],
        class_name: str = "N/A",
    ) -> Self:
        xmin, xmax = box[1] * img_size[1], box[3] * img_size[1]
        ymin, ymax = box[0] * img_size[0], box[2] * img_size[0]
        return cls(xmin, ymin, xmax, ymax, score, class_id, class_name)

    @classmethod
    def from_yolo_detection(cls, box_dict: Dict[str, Any]) -> Self:
        top_left, bottom_right = box_dict["topleft"], box_dict["bottomright"]
        score, class_name = box_dict["confidence"], box_dict["label"]
        return cls(
            top_left["x"],
            top_left["y"],
            bottom_right["x"],
            bottom_right["y"],
            score,
            class_name=class_name,
        )

    def astype(self, newtype: Callable[[Number], Number]) -> Self:
        """Returns a new BoundingBox with coordinates casted as the 'newtype'

        :param newtype: the new type the BoundingBox Coordinates should be (e.g: int, float)
        """
        return self.__class__(
            newtype(self.xmin),
            newtype(self.ymin),
            newtype(self.xmax),
            newtype(self.ymax),
            self.score,
            self.class_id,
            self.class_name,
        )

    @classmethod
    def from_dict(cls, infos: Dict[str, Any]) -> Self:
        """Instantiate a bounding box from a dictionary having proper keys.
        (Usually keys are the attribute name in Uppercase)"""
        return cls(
            xmin=infos["xmin"],
            ymin=infos["ymin"],
            xmax=infos["xmax"],
            ymax=infos["ymax"],
            score=infos["score"],
            class_id=infos["class_id"],
            class_name=infos["class_name"],
        )

    def to_dict(self) -> Dict[str, Any]:
        d = super(DetectionBox, self).to_dict()
        d["score"] = self.score
        d["class_id"] = self.class_id
        d["class_name"] = self.class_name
        return d


class RelativeBoundingBox(BoundingBox):
    """BoundingBox, where all coordinates must be between 0.0 and 1.0."""

    def __init__(self, xmin: Number, ymin: Number, xmax: Number, ymax: Number):
        if not all(0.0 <= c <= 1.0 for c in (xmin, ymin, xmax, ymax)):
            raise ValueError(
                "All coordinates must be between 0 and 1, xmin: {}, ymin: {}, xmax: {}, ymax: {}".format(
                    xmin, ymin, xmax, ymax
                )
            )

        super().__init__(xmin, ymin, xmax, ymax)

    @classmethod
    def from_box_and_shape(cls, box: BoundingBox, shape: Tuple[Number, Number]) -> Self:
        width, height = shape
        return cls(
            box.xmin / width, box.ymin / height, box.xmax / width, box.ymax / height
        )

    def to_global_box(self, width: Number, height: Number) -> BoundingBox:
        return BoundingBox(
            self.xmin * width, self.ymin * height, self.xmax * width, self.ymax * height
        )


class RelativeDetectionBox(RelativeBoundingBox):
    def __init__(
        self,
        xmin: Number,
        ymin: Number,
        xmax: Number,
        ymax: Number,
        class_id: int = 0,
        class_name: str = "N/A",
        score: float = 0.0,
    ) -> None:
        super().__init__(xmin, ymin, xmax, ymax)
        self.class_id = class_id
        self.class_name = class_name
        self.score = score

    @classmethod
    def from_box_and_shape(
        cls,
        box: BoundingBox,
        shape: Tuple[Number, Number],
        class_id: int = 0,
        class_name: str = "N/A",
        score: float = 0.0,
    ) -> Self:
        width, height = shape
        return cls(
            box.xmin / width,
            box.ymin / height,
            box.xmax / width,
            box.ymax / height,
            class_id,
            class_name,
            score,
        )


def normalize_angle_and_shape(
    angle: Number, shape: Tuple[Number, Number]
) -> Tuple[float, Tuple[Number, Number]]:
    """
    Utility function to keep angles and shapes coherent with OpenCV OBB definition
    Angle is the angle between the `width` axis and the X axis.
    """
    angle = angle % 360
    angle = angle if angle < 180 else angle - 180
    if angle >= 90:
        angle = angle - 90
        shape = shape[::-1]
    return angle, shape


class OrientedDetectionBox(DetectionBox):
    """
    Detection box with an angle,
    Angle is applied *after* putting bounding box coordinates
    Angle should be within [0 ; 360[ as we consider that there is no symmetry in the object we are
    annotating (when detecting OBBs for numbers, bounding boxes have to be oriented with
    this kind of angles to differentiate 6 and 9 for instance).
    """

    def __init__(
        self,
        xmin: Number,
        ymin: Number,
        xmax: Number,
        ymax: Number,
        angle: Number = 0,
        symmetries: bool = False,
        score: float = 1.0,
        class_id: int = 0,
        class_name: str = "N/A",
    ) -> None:
        # if angle < 0 or angle > 360:
        #     raise OrientationError("Angle should be in  [0 ; 360[, please use the module (%) operator")
        angle = angle % 360 if angle < 0 or angle >= 360 else angle

        super().__init__(xmin, ymin, xmax, ymax, score, class_id, class_name)
        self.angle = angle
        self.symmetries = symmetries

    def normalize_to_opencv(self, force_symmetries: bool = False) -> Self:
        """
        Return a new OrientedDetectionBox instance with normalized width, height and angle to
        be aligned with Open CV OBB's definition : angle is defined
        by the angle going from the image X axis to the nearest OBB side, it should be within [0; 90[.
        Warning: This can only be used if this OBB does represent an object which have symmetries !
        """
        if not self.symmetries:
            if force_symmetries:
                self.symmetries = True
            else:
                raise OrientationError

        new_angle, new_shape = normalize_angle_and_shape(self.angle, self.shape)
        new_odb = self.__class__(
            xmin=self.xmin,
            ymin=self.ymin,
            xmax=self.xmax,
            ymax=self.ymax,
            angle=new_angle,
            symmetries=True,
            score=self.score,
            class_id=self.class_id,
            class_name=self.class_name,
        )
        new_odb.set_shape(new_shape)
        return new_odb

    @classmethod
    def from_bounding_box_and_angle(
        cls,
        box: BoundingBox,
        angle: float = 0.0,
        score: float = 0.0,
        class_id: int = 0,
        class_name: str = "N/A",
    ) -> Self:
        return cls(
            box.xmin,
            box.ymin,
            box.xmax,
            box.ymax,
            angle=angle,
            score=score,
            class_id=class_id,
            class_name=class_name,
        )

    @classmethod
    def from_detection_box(cls, box: DetectionBox, angle: float = 0) -> Self:
        return cls(
            box.xmin,
            box.ymin,
            box.xmax,
            box.ymax,
            angle=angle,
            score=box.score,
            class_id=box.class_id,
            class_name=box.class_name,
        )

    @classmethod
    def from_opencv(
        cls,
        center: Tuple[Number, Number],
        shape: Tuple[Number, Number],
        angle: float,
        score: float = 1.0,
        class_id: int = 0,
        class_name: str = "N/A",
    ) -> Self:
        """
        Instantiate an oriented bounding box with open cv bounding box definition style.
        Width and height are the bounding box shape before angle is applied.
        Angle is defined by the angle between the closest side of the bb and the X axis,
        it should stay between 0 and 90 degrees. If it is not, then width and height are inversed, and we
        force angle to be in that specific range.
        """
        if angle >= 90 or angle < 0:
            raise OrientationError(
                "Specified angle does not respect open cv OBB definition convention"
                f"(angle ({angle}) is not between in [0; 90[), consider using"
                f"`normalize_angle_and_shape` before instantiating this."
            )

        dx = shape[0] / 2
        dy = shape[1] / 2
        xmin = center[0] - dx
        ymin = center[1] - dy
        xmax = center[0] + dx
        ymax = center[1] + dy

        open_cv_odb = cls(
            xmin,
            ymin,
            xmax,
            ymax,
            angle=angle,
            symmetries=True,
            score=score,
            class_id=class_id,
            class_name=class_name,
        )
        open_cv_odb = open_cv_odb.normalize_to_opencv()
        return open_cv_odb

    def enclosing_box(self) -> DetectionBox:
        """Returns a DetectionBox which englobes the current oriented box
        An enclosing bounding box is equivalent to an AABB (axis aligned bounding box)
        """

        quad: List[Tuple[Number, Number]] = self.to_quad()
        xs, ys = zip(*(point for point in quad))
        return DetectionBox(
            min(xs),
            min(ys),
            max(xs),
            max(ys),
            self.score,
            self.class_id,
            self.class_name,
        )

    def write_node(self, root: et.Element) -> et.Element:
        bndbox = super().write_node(root)
        angle = self.angle if self.angle < 180 else self.angle - 360
        et.SubElement(bndbox, "angle").text = str(float(angle))
        return bndbox

    def to_quad(self) -> List[Tuple[Number, Number]]:
        coords = super().to_quad()
        angle_rad: float = math.radians(self.angle)
        sin = math.sin(angle_rad)
        cos = math.cos(angle_rad)
        center_x, center_y = self.center
        quad: List[Tuple[Number, Number]] = []
        for x, y in coords:
            x_centered = x - center_x
            y_centered = y - center_y
            x_rot = x_centered * cos - y_centered * sin
            y_rot = x_centered * sin + y_centered * cos
            quad.append((x_rot + center_x, y_rot + center_y))
        return quad

    @classmethod
    def from_xml_node(cls, root: et.Element) -> Self:
        return cls(
            int(findtext(root, "xmin")),
            int(findtext(root, "ymin")),
            int(findtext(root, "xmax")),
            int(findtext(root, "ymax")),
            float(findtext(root, "angle")),
        )

    def intersection(self, other: Self) -> Optional[Self]:
        raise NotImplementedError

    def intersect_over_union(self, other: Self) -> float:
        raise NotImplementedError

    def astype(self, newtype: Callable[[Number], Number]) -> Self:
        """Returns a new BoundingBox with coordinates casted as the 'newtype'

        :param newtype: the new type the BoundingBox Coordinates should be (e.g: int, float)
        """
        return self.__class__(
            xmin=newtype(self.xmin),
            ymin=newtype(self.ymin),
            xmax=newtype(self.xmax),
            ymax=newtype(self.ymax),
            angle=self.angle,
            symmetries=self.symmetries,
            score=self.score,
            class_id=self.class_id,
            class_name=self.class_name,
        )

    @classmethod
    def from_dict(cls, infos: Dict[str, Any]) -> Self:
        """Instantiate a bounding box from a dictionary having proper keys.
        (Usually keys are the attribute name in Uppercase)"""
        return cls(
            xmin=infos["xmin"],
            ymin=infos["ymin"],
            xmax=infos["xmax"],
            ymax=infos["ymax"],
            angle=infos["angle"],
            score=infos["score"],
            class_id=infos["class_id"],
            class_name=infos["class_name"],
        )

    def to_dict(self) -> Dict[str, Any]:
        d = super(OrientedDetectionBox, self).to_dict()
        d["angle"] = self.angle
        return d

    def __iter__(self) -> Iterator[Number]:
        """Returns an iterator over coordinates"""
        return (
            getattr(self, p) for p in ["xmin", "ymin", "xmax", "ymax", "angle", "score"]
        )

    def __hash__(self) -> int:
        return hash(
            (
                self.xmin,
                self.ymin,
                self.xmax,
                self.ymax,
                self.angle,
                self.class_name,
                self.class_id,
                self.score,
            )
        )

    def __eq__(self, other: object) -> bool:
        if not super().__eq__(other):
            return False
        if not isinstance(other, OrientedDetectionBox):
            raise NotImplementedError
        return all(
            [
                self.angle == other.angle,
                self.class_name == other.class_name,
                self.class_id == other.class_id,
                self.score == other.score,
            ]
        )

    def __repr__(self) -> str:
        return f"{super().__repr__()} angle: {self.angle}"
